import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do I calculate the cost of a road trip?", a: "Divide the total miles by your car's MPG to get gallons needed. Multiply gallons by the price per gallon. For example: 500 miles  x  30 MPG = 16.67 gallons  x  $3.50 = $58.33." },
  { q: "How much does it cost per mile to drive?", a: "Cost per mile = Gas price  x  MPG. At $3.50/gallon with 30 MPG, it costs $0.117 per mile. This does not include depreciation, insurance, or maintenance costs." },
  { q: "What is the most fuel-efficient driving speed?", a: "Most vehicles achieve peak fuel efficiency at 45-65 mph. Above 65 mph, aerodynamic drag increases sharply, reducing MPG. Driving at 75 mph instead of 65 mph can decrease fuel economy by 15-20%." },
  { q: "How does driving style affect fuel cost?", a: "Aggressive driving (rapid acceleration, hard braking) can reduce fuel economy by 15-30%. Smooth acceleration, maintaining steady speed, and avoiding idling can significantly improve MPG and reduce fuel costs." },
  { q: "How do I find my car's MPG?", a: "Fill your tank, reset your trip odometer. Drive normally until you need to refill. Divide the miles driven by the gallons needed to refill the tank. For a more accurate figure, repeat over multiple fill-ups and average the results." },
  { q: "How much does gas cost for a 1,000-mile road trip?", a: "It depends on your vehicle's fuel economy and gas price. At 25 MPG and $3.50/gallon: 1,000  x  25 = 40 gallons  x  $3.50 = $140. At 20 MPG and $4.00/gallon: 1,000  x  20 = 50 gallons  x  $4.00 = $200." },
  { q: "Is it cheaper to drive or fly?", a: "For trips under 300-400 miles, driving is often cheaper, especially with multiple passengers sharing fuel cost. For longer trips, compare total fuel cost vs. flight price plus ground transportation on each end. Factor in time savings when flying." },
];

export default function FuelCostCalculator() {
  useCurrencyVersion();
  const [distance, setDistance] = useState(300);
  const [mpg, setMpg] = useState(30);
  const [pricePerGallon, setPricePerGallon] = useState(3.50);

  const gallons = distance / mpg;
  const cost = gallons * pricePerGallon;
  const costPerMile = pricePerGallon / mpg;
  const fmt = (n: number) => formatCurrencyValue(n, { minimumFractionDigits: 2 });

  return (
    <>
      <SEOHead
        title="Free Fuel Cost Calculator Online - Calculate Road Trip Fuel Cost Instantly | CalcHive"
        description="Free online fuel cost calculator. Calculate the total fuel cost for any road trip from distance, MPG and gas price instantly. 100% free for everyone, no signup required."
        canonical="/fuel-cost-calculator"
        keywords="free fuel cost calculator, road trip fuel cost calculator free online, calculate gas cost for trip free, fuel cost estimator free, trip gas cost calculator free"
        category="Automotive Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-950/50 px-3 py-1 rounded-full mb-4 inline-block">Transportation</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Fuel Cost Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free fuel cost calculator to calculate gas cost for trip free from distance, MPG, and gas price. This road trip fuel cost calculator free online also works as a fuel cost estimator free and trip gas cost calculator free for every driver.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="distance" label="Trip Distance (miles)" value={distance} min={1} max={5000} step={1} onChange={setDistance} format={v => `${v.toLocaleString()} miles`} testId="input-distance" />
            <SliderInput id="mpg" label="Fuel Economy (MPG)" value={mpg} min={5} max={150} step={0.5} onChange={setMpg} format={v => `${v} MPG`} testId="input-mpg" />
            <SliderInput id="price" label="Gas Price" value={pricePerGallon} min={0.50} max={8} step={0.01} onChange={setPricePerGallon} format={v => `${fmt(v)}/gal`} testId="input-price" />
          </div>
          <motion.div key={`${distance}-${mpg}-${pricePerGallon}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-rose-500 to-rose-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Total Fuel Cost</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-cost">{fmt(cost)}</p>
              <p className="text-white/70 text-sm mt-1">for {distance.toLocaleString()} miles</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "Gallons Needed", value: gallons.toFixed(2) }, { label: "Cost Per Mile", value: fmt(costPerMile) }, { label: "Cost Per 100 Miles", value: fmt(costPerMile * 100) }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Road Trip Fuel Cost for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Fuel cost depends on three things: how far you're going, how efficiently your vehicle uses fuel (MPG), and how much gas costs per gallon. The formula is simple and gives you an accurate estimate for any trip.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Gallons Needed = Distance (miles)  x  Fuel Economy (MPG)</p>
            <p>Total Fuel Cost = Gallons Needed  x  Gas Price ($/gallon)</p>
            <p>Cost Per Mile = Gas Price  x  MPG</p>
            <p className="text-xs text-muted-foreground mt-2">Example: 400 miles, 25 MPG, $3.80/gallon</p>
            <p>Gallons = 400  x  25 = 16 gallons</p>
            <p>Cost = 16  x  $3.80 = $60.80</p>
            <p>Per Mile = $3.80  x  25 = $0.152/mile</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Distance MPG and Gas Price Affect Your Fuel Cost</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Vehicle Type", "Avg MPG", "Cost/Mile", "Cost per 100 mi", "Annual Cost (15K mi)"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Compact Car", "35 MPG", "$0.10", "$10.00", "$1,500"],
                  ["Midsize Sedan", "30 MPG", "$0.117", "$11.67", "$1,750"],
                  ["Full-Size SUV", "20 MPG", "$0.175", "$17.50", "$2,625"],
                  ["Pickup Truck", "18 MPG", "$0.194", "$19.44", "$2,917"],
                  ["Minivan", "22 MPG", "$0.159", "$15.91", "$2,386"],
                  ["Hybrid Car", "50 MPG", "$0.07", "$7.00", "$1,050"],
                  ["Large Truck (diesel)", "10 MPG", "$0.35", "$35.00", "$5,250"],
                ].map(([type, ...cells]) => (
                  <tr key={type} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{type}</td>
                    {cells.map((c, i) => <td key={i} className="py-2.5 px-3 text-muted-foreground">{c}</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Road Trip Cost Estimator for Every Driver</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Route (approx. distance)", "25 MPG @ $3.50", "30 MPG @ $3.50", "20 MPG @ $4.00"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["NYC to Boston (215 mi)", "$30.10", "$25.08", "$43.00"],
                  ["LA to Las Vegas (270 mi)", "$37.80", "$31.50", "$54.00"],
                  ["NYC to Miami (1,280 mi)", "$179.20", "$149.33", "$256.00"],
                  ["Chicago to Denver (1,000 mi)", "$140.00", "$116.67", "$200.00"],
                  ["LA to Seattle (1,140 mi)", "$159.60", "$133.00", "$228.00"],
                  ["Dallas to Denver (925 mi)", "$129.50", "$107.92", "$185.00"],
                ].map(([route, ...cells]) => (
                  <tr key={route} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{route}</td>
                    {cells.map((c, i) => <td key={i} className="py-2.5 px-4 text-muted-foreground">{c}</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h3 className="text-2xl font-bold text-foreground">Tips to Reduce Your Fuel Costs</h3>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li><strong className="text-foreground">Drive at optimal speed.</strong> Most cars achieve best MPG between 45-65 mph. Each 5 mph over 65 mph reduces fuel economy by 7-14%.</li>
            <li><strong className="text-foreground">Accelerate and brake smoothly.</strong> Aggressive driving reduces fuel economy 15-30%. Anticipate stops and coast to a gentle deceleration.</li>
            <li><strong className="text-foreground">Keep tires properly inflated.</strong> Under-inflated tires reduce MPG by 0.2% for every 1 PSI drop. Check monthly and before long trips.</li>
            <li><strong className="text-foreground">Use cruise control on highways.</strong> Maintaining a steady speed eliminates unnecessary acceleration and braking, improving highway MPG by 7-14%.</li>
            <li><strong className="text-foreground">Use a gas price app.</strong> Apps like GasBuddy can find stations 20-30 cents per gallon cheaper than others in your area, saving $3-5 per fill-up.</li>
            <li><strong className="text-foreground">Avoid excessive idling.</strong> Idling gets 0 MPG. Turn off the engine if stopped for more than 30 seconds (modern engines use less fuel restarting than idling for 30+ seconds).</li>
          </ul>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/fuel-cost-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


